// Backward compat alias
export const blogPosts = blogPostsMeta

export const blogCategories: string[] = [...new Set(blogPostsMeta.map(p => p.category))]

export function getBlogPostMeta(slug: string): BlogPostMeta | undefined {
  return blogPostsMeta.find(p => p.slug === slug)
}

export function getRecentPostsMeta(count: number = 3): BlogPostMeta[] {
  return [...blogPostsMeta].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, count)
}

// Legacy aliases for backward compat
export const getRecentPosts = getRecentPostsMeta

export function getRelatedPostsMeta(currentSlug: string, category: string, limit: number = 3): BlogPostMeta[] {
  return blogPostsMeta
    .filter(p => p.slug !== currentSlug && p.category === category)
    .slice(0, limit)
}

